input.content:
const PROCESSING_FEE = 5;

type Item = { type: string };
type Step = { op: "quote"; items: Item[] };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
};

export const runScenario = (scenario: Scenario): unknown => {
  const results = scenario.steps.map((step) => {
    const itemsTotal = step.items.reduce(
      (sum, item) => sum + (BASE_PREMIUMS[item.type] ?? 0),
      0,
    );
    return { premium: itemsTotal + PROCESSING_FEE };
  });
  return { results };
};

