const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);

const countByType = (items: Item[]): Map<string, number> => {
  const counts = new Map<string, number>();
  for (const item of items) {
    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
  }
  return counts;
};

const componentTypeBase = (count: number): number =>
  count === 3 ? BLOCK_OF_THREE_BASE : count * COMPONENT_BASE;

const sum = (values: number[]): number => values.reduce((a, b) => a + b, 0);

const mainItemBase = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;

const mainItemSurcharge = (item: Item): number =>
  item.cursed ? mainItemBase(item) * CURSED_SURCHARGE_RATE : 0;

const mainItemsBase = (items: Item[]): number =>
  sum(items.filter((item) => !isComponent(item)).map(mainItemBase));

const componentsBase = (items: Item[]): number => {
  const counts = countByType(items.filter(isComponent));
  return sum([...counts.values()].map(componentTypeBase));
};

const itemSurcharges = (items: Item[]): number => sum(items.map(mainItemSurcharge));

const policyBase = (items: Item[]): number => mainItemsBase(items) + componentsBase(items);

const quote = (step: QuoteStep): QuoteResult => {
  const base = policyBase(step.items);
  const surcharges = itemSurcharges(step.items);
  const firstInsurance = base * FIRST_INSURANCE_RATE;
  return { premium: Math.ceil(base + surcharges + firstInsurance + PROCESSING_FEE) };
};

export const runScenario = (scenario: Scenario): ScenarioResult => ({
  results: scenario.steps.map(quote),
});

