import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Quote — base premiums and processing fee
  it("empty item list quote returns premium 5 (processing fee only)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });
  it("single sword quote newcomer returns 115 (100 + 10 first ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("single amulet quote newcomer returns 71 (60 + 6 first ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("single staff quote newcomer returns 93 (80 + 8 first ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "staff", material: "wood", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 93 }] });
  });
  it("single potion quote newcomer returns 49 (40 + 4 first ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "potion", material: "glass", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 49 }] });
  });
  it("multiple items sum their base premiums plus first ins plus fee", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "sword", material: "steel", enchantment: 0, cursed: false },
            { type: "amulet", material: "silver", enchantment: 0, cursed: false },
            { type: "potion", material: "glass", enchantment: 0, cursed: false },
          ],
        },
      ],
    });
    // base = 100 + 60 + 40 = 200; first ins +20 = 220; +5 fee = 225
    expect(result).toEqual({ results: [{ premium: 225 }] });
  });

  // Components and building blocks
  it("2 runes quote newcomer returns 60 (50 + 5 first ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 60 }] });
  });
  it("3 runes quote newcomer returns 71 (60 block + 6 first ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("4 runes quote newcomer returns 115 (100 + 10 first ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
          ],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("7 runes quote newcomer returns 198 (175 + 17.5 first ins + 5 fee rounded up)", () => {
    const items = Array.from({ length: 7 }, () => ({ type: "rune" }));
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items }],
    });
    // 175 + 17.5 + 5 = 197.5 → rounded up = 198
    expect(result).toEqual({ results: [{ premium: 198 }] });
  });
  it("2 runes + 1 moonstone quote newcomer returns 88 (75 + 7.5 first ins + 5 fee rounded up)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }],
        },
      ],
    });
    // 75 + 7.5 + 5 = 87.5 → rounded up = 88
    expect(result).toEqual({ results: [{ premium: 88 }] });
  });
  it("3 runes + 3 moonstones quote newcomer returns 137 (120 + 12 first ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
            { type: "moonstone" },
            { type: "moonstone" },
            { type: "moonstone" },
          ],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 137 }] });
  });

  // Item-specific modifiers
  it("cursed sword adds 50% surcharge on item base", () => {
    // Newcomer with a cursed sword (steel, enchantment 3)
    // 100 base + 50 curse + 10 first insurance + 5 fee = 165
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: true }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 165 }] });
  });
  it("highly enchanted item (level 5) adds 30% surcharge", () => {
    // 100 base + 30 high-ench + 10 first ins + 5 fee = 145
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 5, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 145 }] });
  });
  it.todo("enchantment 4 does not trigger high-enchantment surcharge");
  it.todo("cursed + high enchantment both apply to item base");

  // Policy-wide modifiers
  it.todo("long-standing customer (2+ years) gets 20% loyalty discount on policy base");
  it.todo("follow-up contract (after first) gets 15% discount on policy base");

  // Modifier scope on multi-item policies
  it.todo("item-specific modifier applies only to that item, not the whole policy");

  // Integration examples
  it.todo("long-standing customer's second contract integration example -> 160");

  // Rounding
  it.todo("premium is rounded up (MHPCO favor)");

  // Unknown item type
  it.todo("unknown item type in quote throws an error");

  // Claim — basic payout
  it.todo("regular sword damage 500 returns payout 400 (500 - 100 deductible)");
  it.todo("rune damage 200 returns payout 100 (200 - 100 deductible)");

  // Claim — special clauses
  it.todo("enchantment 8+ item damage is reimbursed at 50% then deductible");
  it.todo("dragon-material item damage is fully reimbursed then deductible");
  it.todo("dragon + enchantment 9: 50% rule wins, then deductible");
  it.todo("dragon-material with enchantment 5: only dragon clause applies");

  // Claim — multiple damages, deductible per event
  it.todo("multiple item damages each get their own deductible");

  // Claim — cap
  it.todo("payout capped at twice the insurance sum");
  it.todo("cap is based on unmodified insurance value");
  it.todo("successive claims reduce the remaining cap");

  // Claim — multiple items of same type
  it.todo("policy with two swords: insurance sum 2000, cap 4000");
  it.todo("damage entries exceeding insured count of that type rejects claim");

  // Claim — errors
  it.todo("claim referencing item not in policy throws an error");
  it.todo("claim with negative damage amount throws an error");

  // Payout rounding
  it.todo("payout is rounded down (MHPCO favor)");
});

