   - Item-specific vs policy-wide modifiers
   - Math.ceil for premium rounding (MHPCO favor)

3. Files and Code Sections:

   - **prompt.md**: The kata spec with all rules, examples, integration examples, edge cases, and CLI format.

   - **src/claim-office.spec.ts**: Test file with describe block "MHPCO Claim Office". 19 active tests, 18 todos.

   - **src/claim-office.ts** (current state):
     ```typescript
     const PROCESSING_FEE = 5;
     const COMPONENT_BASE = 25;
     const BLOCK_OF_THREE_BASE = 60;
     const CURSED_SURCHARGE_RATE = 0.5;
     const HIGH_ENCHANTMENT_RATE = 0.3;
     const HIGH_ENCHANTMENT_THRESHOLD = 5;
     const FIRST_INSURANCE_RATE = 0.1;
     const LOYALTY_DISCOUNT_RATE = 0.2;
     const LOYALTY_YEARS_THRESHOLD = 2;
     const FOLLOW_UP_DISCOUNT_RATE = 0.15;

     const BASE_PREMIUMS: Record<string, number> = {
       sword: 100, amulet: 60, staff: 80, potion: 40,
     };
     const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

     type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean; };
     type QuoteStep = { op: "quote"; items: Item[] };
     type Customer = { yearsWithMHPCO: number };
     type Scenario = { customer: Customer; steps: QuoteStep[] };
     type QuoteResult = { premium: number };
     type ScenarioResult = { results: QuoteResult[] };

     const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
     const countByType = (items: Item[]): Map<string, number> => { ... }
     const componentTypeBase = (count: number): number =>
       count === 3 ? BLOCK_OF_THREE_BASE : count * COMPONENT_BASE;
     const sum = (values: number[]): number => values.reduce((a, b) => a + b, 0);
     const mainItemBase = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
     const mainItemSurcharge = (item: Item): number => {
       const base = mainItemBase(item);
       const cursed = item.cursed ? base * CURSED_SURCHARGE_RATE : 0;
       const highEnch = (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD ? base * HIGH_ENCHANTMENT_RATE : 0;
       return cursed + highEnch;
     };
     const mainItemsBase = (items: Item[]): number =>
       sum(items.filter((item) => !isComponent(item)).map(mainItemBase));
     const componentsBase = (items: Item[]): number => {
       const counts = countByType(items.filter(isComponent));
       return sum([...counts.values()].map(componentTypeBase));
     };
     const itemSurcharges = (items: Item[]): number => sum(items.map(mainItemSurcharge));
     const policyBase = (items: Item[]): number => mainItemsBase(items) + componentsBase(items);
     const loyaltyDiscount = (base: number, customer: Customer): number =>
       customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? base * LOYALTY_DISCOUNT_RATE : 0;

     const quote = (step: QuoteStep, customer: Customer, isFollowUp: boolean): QuoteResult => {
       const base = policyBase(step.items);
       const surcharges = itemSurcharges(step.items);
       const firstInsurance = base * FIRST_INSURANCE_RATE;
       const loyalty = loyaltyDiscount(base, customer);
       const followUp = isFollowUp ? base * FOLLOW_UP_DISCOUNT_RATE : 0;
       return {
         premium: Math.ceil(base + surcharges + firstInsurance - loyalty - followUp + PROCESSING_FEE),
       };
     };

     export const runScenario = (scenario: Scenario): ScenarioResult => ({
       results: scenario.steps.map((step, index) => quote(step, scenario.customer, index > 0)),
     });
